namespace make3d {
namespace fs = std::filesystem;
namespace {
static bool WantsGenericReconstruction(const ProductionPipelineOptions& o){return o.exportRaw||o.exportPolished||o.exportVoxelVolume;}
static fs::path DebugFallbackRoot(const fs::path& out){return out/"debug_fallback";}
static void WriteDebugMask(const fs::path& p,int w,int h,const std::vector<std::uint8_t>& m){std::vector<std::uint8_t> rgb((size_t)w*h*3,0);for(int i=0;i<w*h;++i){std::uint8_t v=m[(size_t)i]?255:0;rgb[(size_t)i*3]=v;rgb[(size_t)i*3+1]=v;rgb[(size_t)i*3+2]=v;}SaveDebugPPM(p,w,h,rgb,nullptr);}
static void WriteDebugDepth(const fs::path& p,int w,int h,const DepthImage& d){std::vector<std::uint8_t> rgb((size_t)w*h*3,0);for(int i=0;i<w*h;++i){float v=d.values[(size_t)i];if(v<0)v=0;if(v>1)v=1;std::uint8_t b=(std::uint8_t)(v*255.0f);rgb[(size_t)i*3]=b;rgb[(size_t)i*3+1]=b;rgb[(size_t)i*3+2]=b;}SaveDebugPPM(p,w,h,rgb,nullptr);}
static std::string MaybePath(const fs::path& p,const char* disabled){return p.empty()?std::string(disabled):p.generic_string();}
static bool DebugMeshIsSafe(const MeshData& mesh,const char* label,ProductionPipelineResult& r){MeshQualityGateReport q=AnalyzeMeshQualityGate(mesh);if(q.ok)return true;std::ostringstream s;s<<label<<" fallback mesh skipped by Phase 0 safe-output quality gate.";for(const auto& w:q.warnings)s<<" "<<w;r.reconstructionReport.warnings.push_back(s.str());return false;}
static std::string MakeProductionMarkdown(const ProductionPipelineResult& r){std::ostringstream o;o<<"# Make3D Production Pipeline Report\n\n";o<<"## Review target\n\nOpen this first:\n\n```text\n"<<MaybePath(r.heroVertexColorGltfPath,"hero output not generated")<<"\n```\n\n";o<<"The hero character and game-asset outputs are the primary safe artifacts. Raw, polished, and voxel reconstruction are debug-only fallback outputs and are disabled in the standard review sample.\n\n";if(!r.gameAssetMesh.positions.empty()){o<<"## Generic game asset\n\n"<<r.gameAssetReport.classification.ToMarkdown()<<"\n";o<<"### Game asset mesh validation\n\n"<<r.gameAssetReport.validation.ToMarkdown()<<"\n";o<<"### Game asset Phase 0 quality gate\n\n"<<r.gameAssetReport.qualityGate.ToMarkdown()<<"\n";o<<"### Game asset metadata\n\n"<<r.gameAssetReport.metadata.ToMarkdown()<<"\n";}o<<"## Shape inference\n\n"<<r.shapeInferenceReport.ToMarkdown()<<"\n";o<<"## Learned shape model\n\n"<<r.learnedShapeReport.ToMarkdown()<<"\n";o<<"## Hero character reconstruction\n\n"<<r.heroReport.ToMarkdown()<<"\n";o<<"## Reconstruction\n\n"<<r.reconstructionReport.ToMarkdown()<<"\n";o<<"## Mask refinement\n\n"<<r.maskReport.ToMarkdown()<<"\n";if(!r.polishedMesh.positions.empty())o<<"## Debug fallback mesh polish\n\n"<<r.polishReport.ToMarkdown()<<"\n";if(!r.voxelMesh.positions.empty())o<<"## Debug fallback voxel-style volume\n\n"<<r.voxelReport.ToMarkdown()<<"\n";o<<"## Output files\n\n";o<<"- "<<MaybePath(r.heroObjPath,"hero OBJ disabled or failed")<<"\n";o<<"- "<<MaybePath(r.heroMaterialGltfPath,"hero material glTF disabled or failed")<<"\n";o<<"- "<<MaybePath(r.heroVertexColorGltfPath,"hero semantic vertex-color glTF disabled or failed")<<"\n";if(!r.gameAssetObjPath.empty())o<<"- "<<r.gameAssetObjPath.generic_string()<<"\n";if(!r.gameAssetGltfPath.empty())o<<"- "<<r.gameAssetGltfPath.generic_string()<<"\n";if(!r.gameAssetReportPath.empty())o<<"- "<<r.gameAssetReportPath.generic_string()<<"\n";if(!r.gameAssetManifestPath.empty())o<<"- "<<r.gameAssetManifestPath.generic_string()<<"\n";if(!r.rawObjPath.empty())o<<"- "<<r.rawObjPath.generic_string()<<"\n";if(!r.polishedObjPath.empty())o<<"- "<<r.polishedObjPath.generic_string()<<"\n";if(!r.voxelObjPath.empty())o<<"- "<<r.voxelObjPath.generic_string()<<"\n";o<<"- debug_mask_refined.ppm\n- debug_depth_refined.ppm\n- debug_depth_inferred.ppm\n- debug_depth_learned.ppm\n";return o.str();}
static std::string MakeProductionJson(const ProductionPipelineResult& r){std::ostringstream o;o<<"{\n";o<<"  \"reviewTarget\": \""<<MaybePath(r.heroVertexColorGltfPath,"")<<"\",\n";o<<"  \"fallbackMode\": \"debug-only\",\n";o<<"  \"shapeInference\": "<<r.shapeInferenceReport.ToJson()<<",\n";o<<"  \"learnedShape\": "<<r.learnedShapeReport.ToJson()<<",\n";o<<"  \"heroCharacter\": "<<r.heroReport.ToJson()<<",\n";o<<"  \"reconstruction\": "<<r.reconstructionReport.ToJson()<<",\n";o<<"  \"maskRefine\": "<<r.maskReport.ToJson()<<",\n";o<<"  \"polish\": "<<r.polishReport.ToJson()<<",\n";o<<"  \"voxelVolume\": "<<r.voxelReport.ToJson()<<",\n";o<<"  \"gameAssetType\": \""<<ToString(r.gameAssetReport.classification.assetType)<<"\",\n";o<<"  \"gameAssetObj\": \""<<MaybePath(r.gameAssetObjPath,"")<<"\",\n";o<<"  \"gameAssetGltf\": \""<<MaybePath(r.gameAssetGltfPath,"")<<"\",\n";o<<"  \"gameAssetReport\": \""<<MaybePath(r.gameAssetReportPath,"")<<"\",\n";o<<"  \"gameAssetManifest\": \""<<MaybePath(r.gameAssetManifestPath,"")<<"\",\n";o<<"  \"gameAssetQualityGate\": "<<r.gameAssetReport.qualityGate.ToJson()<<",\n";o<<"  \"heroMaterialGltf\": \""<<MaybePath(r.heroMaterialGltfPath,"")<<"\",\n";o<<"  \"heroVertexColorGltf\": \""<<MaybePath(r.heroVertexColorGltfPath,"")<<"\",\n";o<<"  \"rawMaterialGltf\": \""<<MaybePath(r.rawMaterialGltfPath,"")<<"\",\n";o<<"  \"polishedMaterialGltf\": \""<<MaybePath(r.polishedMaterialGltfPath,"")<<"\",\n";o<<"  \"polishedVertexColorGltf\": \""<<MaybePath(r.polishedVertexColorGltfPath,"")<<"\",\n";o<<"  \"voxelMaterialGltf\": \""<<MaybePath(r.voxelMaterialGltfPath,"")<<"\",\n";o<<"  \"voxelVertexColorGltf\": \""<<MaybePath(r.voxelVertexColorGltfPath,"")<<"\"\n}\n";return o.str();}
static void WriteReportsAndDebugImages(const fs::path& out,const ImageRGBA& color,const std::vector<std::uint8_t>& mask,const DepthImage& depth,const DepthImage& inferred,const DepthImage& recon,ProductionPipelineResult& r,const ProductionPipelineOptions& opt){if(opt.writeDebugImages){WriteDebugMask(out/"debug_mask_refined.ppm",color.width,color.height,mask);WriteDebugDepth(out/"debug_depth_refined.ppm",color.width,color.height,depth);WriteDebugDepth(out/"debug_depth_inferred.ppm",color.width,color.height,inferred);WriteDebugDepth(out/"debug_depth_learned.ppm",color.width,color.height,recon);}if(opt.writeReports){r.productionReportPath=out/"production_report.md";std::ofstream md(r.productionReportPath,std::ios::binary);md<<MakeProductionMarkdown(r);std::ofstream js(out/"production_report.json",std::ios::binary);js<<MakeProductionJson(r);}}
static bool BuildProductionGameAsset(const ImageRGBA& color,const DepthImage& depth,const std::vector<std::uint8_t>& mask,const fs::path& out,const ProductionPipelineOptions& opt,ProductionPipelineResult& r){if(!opt.exportGameAsset)return true;r.gameAssetReport=BuildGenericGameAsset(color,depth,mask,out/"game_asset",opt.gameAsset);if(!r.gameAssetReport.ok){r.message=r.gameAssetReport.message;return false;}r.gameAssetMesh=r.gameAssetReport.mesh;r.gameAssetObjPath=r.gameAssetReport.objPath;r.gameAssetGltfPath=r.gameAssetReport.gltfPath;r.gameAssetReportPath=r.gameAssetReport.reportPath;r.gameAssetManifestPath=r.gameAssetReport.manifestPath;return true;}
} // namespace

ProductionPipelineResult BuildProductionModelFromImage(const fs::path& colorPath,const std::optional<fs::path>& depthPath,const fs::path& outputDir,const ProductionPipelineOptions& options){ProductionPipelineResult result;std::string error;auto color=LoadImageRGBA(colorPath,&error);if(!color){result.message=error;return result;}std::optional<DepthImage> providedDepth;if(depthPath)providedDepth=LoadDepthImage(*depthPath,&error);fs::create_directories(outputDir);fs::create_directories(outputDir/"hero");if(options.exportGameAsset)fs::create_directories(outputDir/"game_asset");if(WantsGenericReconstruction(options)){fs::create_directories(DebugFallbackRoot(outputDir));if(options.exportRaw)fs::create_directories(DebugFallbackRoot(outputDir)/"raw");if(options.exportPolished)fs::create_directories(DebugFallbackRoot(outputDir)/"polished");if(options.exportVoxelVolume)fs::create_directories(DebugFallbackRoot(outputDir)/"voxel");}
result.reconstructionReport.imageWidth=color->width;result.reconstructionReport.imageHeight=color->height;std::vector<std::uint8_t> mask=BuildForegroundMask(*color,&result.reconstructionReport);if(result.reconstructionReport.foregroundPixels==0){result.message="Foreground extraction failed.";return result;}result.maskReport=RefineForegroundMask(mask,color->width,color->height,options.maskRefine);result.reconstructionReport.foregroundPixels=result.maskReport.foregroundAfter;result.reconstructionReport.foregroundCoverage=(float)result.maskReport.foregroundAfter/(float)(color->width*color->height);DepthImage depth=PrepareDepth(*color,providedDepth,mask,options.reconstruction,&result.reconstructionReport);DepthImage reconstructionDepth=depth;if(options.enableShapeInference){result.shapeInferenceReport=RunShapeInference(*color,mask,depth,options.shapeInference);if(!result.shapeInferenceReport.adjustedDepth.values.empty())reconstructionDepth=result.shapeInferenceReport.adjustedDepth;}DepthImage inferredDepth=reconstructionDepth;if(options.enableLearnedShapeModel){result.learnedShapeReport=RunLearnedShapeModel(*color,mask,reconstructionDepth,result.shapeInferenceReport,options.learnedShape);if(result.learnedShapeReport.ok&&!result.learnedShapeReport.learnedDepth.values.empty())reconstructionDepth=result.learnedShapeReport.learnedDepth;}
if(options.exportHeroCharacter){result.heroMesh=BuildHeroCharacterMesh(*color,reconstructionDepth,mask,options.heroCharacter,&result.heroReport);AddHeroDetailVolumes(result.heroMesh,options.heroCharacter,&result.heroReport);AddHeroFineDetails(result.heroMesh,options.heroCharacter);result.heroReport.vertices=(int)(result.heroMesh.positions.size()/3);result.heroReport.triangles=(int)(result.heroMesh.indices.size()/3);if(result.heroMesh.positions.empty()||result.heroMesh.indices.empty()){result.message="Hero character reconstruction failed.";return result;}result.heroObjPath=outputDir/"hero"/"make3d_hero_character.obj";result.heroMaterialGltfPath=outputDir/"hero"/"make3d_hero_character_material.gltf";result.heroVertexColorGltfPath=outputDir/"hero"/"make3d_hero_character_vertex_color.gltf";GltfMaterialOptions hm;hm.materialName="Make3DHeroCharacterMaterial";hm.baseColorFactor={0.76f,0.70f,0.64f,1.0f};if(!ExportOBJ(result.heroMesh,result.heroObjPath,"",&error)){result.message=error;return result;}if(!ExportGLTFWithMaterial(result.heroMesh,result.heroMaterialGltfPath,hm,&error)){result.message=error;return result;}if(options.exportVertexColorGltf){HeroSemanticPalette p=ExtractHeroSemanticPalette(*color,mask);HeroSemanticGltfOptions so;so.materialName="Make3DHeroSemanticVertexColorMaterial";if(!ExportHeroSemanticGLTF(result.heroMesh,p,result.heroVertexColorGltfPath,so,&error)){result.message=error;return result;}}}
if(!BuildProductionGameAsset(*color,reconstructionDepth,mask,outputDir,options,result))return result;
if(WantsGenericReconstruction(options)){result.rawMesh=ReconstructMesh(*color,reconstructionDepth,mask,options.reconstruction,&result.reconstructionReport);if(result.rawMesh.positions.empty()||result.rawMesh.indices.empty()){result.reconstructionReport.warnings.push_back("Raw debug fallback reconstruction failed and was not exported.");}else{if(options.exportRaw&&DebugMeshIsSafe(result.rawMesh,"Raw",result)){result.rawObjPath=DebugFallbackRoot(outputDir)/"raw"/"make3d_raw.obj";result.rawMaterialGltfPath=DebugFallbackRoot(outputDir)/"raw"/"make3d_raw_material.gltf";if(!ExportOBJ(result.rawMesh,result.rawObjPath,"",&error)){result.message=error;return result;}GltfMaterialOptions m;m.materialName="Make3DDebugRawMaterial";m.baseColorFactor={0.62f,0.62f,0.62f,1.0f};if(!ExportGLTFWithMaterial(result.rawMesh,result.rawMaterialGltfPath,m,&error)){result.message=error;return result;}}result.polishedMesh=result.rawMesh;result.polishReport=PolishMesh(result.polishedMesh,options.polish);if(options.exportPolished&&DebugMeshIsSafe(result.polishedMesh,"Polished",result)){result.polishedObjPath=DebugFallbackRoot(outputDir)/"polished"/"make3d_polished.obj";result.polishedMaterialGltfPath=DebugFallbackRoot(outputDir)/"polished"/"make3d_polished_material.gltf";result.polishedVertexColorGltfPath=DebugFallbackRoot(outputDir)/"polished"/"make3d_polished_vertex_color.gltf";if(!ExportOBJ(result.polishedMesh,result.polishedObjPath,"",&error)){result.message=error;return result;}GltfMaterialOptions m;m.materialName="Make3DDebugPolishedMaterial";m.baseColorFactor={0.72f,0.78f,0.86f,1.0f};if(!ExportGLTFWithMaterial(result.polishedMesh,result.polishedMaterialGltfPath,m,&error)){result.message=error;return result;}if(options.exportVertexColorGltf){VertexColorGltfOptions co;co.materialName="Make3DDebugPolishedVertexColorMaterial";if(!ExportGLTFWithVertexColors(result.polishedMesh,*color,result.polishedVertexColorGltfPath,co,&error)){result.message=error;return result;}}}}if(options.exportVoxelVolume){result.voxelMesh=BuildVoxelVolumeMesh(*color,reconstructionDepth,mask,options.voxel,&result.voxelReport);if(!result.voxelMesh.positions.empty()&&!result.voxelMesh.indices.empty()){MeshPolishOptions vp=options.polish;vp.keepLargestComponentOnly=true;vp.smoothingIterations=std::max(2,options.polish.smoothingIterations/2);PolishMesh(result.voxelMesh,vp);if(DebugMeshIsSafe(result.voxelMesh,"Voxel",result)){result.voxelObjPath=DebugFallbackRoot(outputDir)/"voxel"/"make3d_voxel_volume.obj";result.voxelMaterialGltfPath=DebugFallbackRoot(outputDir)/"voxel"/"make3d_voxel_volume_material.gltf";result.voxelVertexColorGltfPath=DebugFallbackRoot(outputDir)/"voxel"/"make3d_voxel_volume_vertex_color.gltf";GltfMaterialOptions m;m.materialName="Make3DDebugVoxelVolumeMaterial";m.baseColorFactor={0.66f,0.76f,0.90f,1.0f};if(!ExportOBJ(result.voxelMesh,result.voxelObjPath,"",&error)){result.message=error;return result;}if(!ExportGLTFWithMaterial(result.voxelMesh,result.voxelMaterialGltfPath,m,&error)){result.message=error;return result;}if(options.exportVertexColorGltf){VertexColorGltfOptions co;co.materialName="Make3DDebugVoxelVertexColorMaterial";if(!ExportGLTFWithVertexColors(result.voxelMesh,*color,result.voxelVertexColorGltfPath,co,&error)){result.message=error;return result;}}}}else result.reconstructionReport.warnings.push_back("Voxel debug fallback reconstruction failed and was not exported.");}}
WriteReportsAndDebugImages(outputDir,*color,mask,depth,inferredDepth,reconstructionDepth,result,options);result.ok=true;result.message=WantsGenericReconstruction(options)?"Production pipeline finished with debug-only fallback reconstruction gated by Phase 0 safe-output validation.":"Production pipeline finished in hero-only review mode.";return result;}
} // namespace make3d
